ALTER TABLE IF EXISTS public.sipro_detalle_consolidado_registros
    ALTER COLUMN documento TYPE bigint USING documento::bigint;

CREATE TABLE IF NOT EXISTS public.sipro_parametros_columnas_creffsos (
    id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    nombre_columna character varying(100) NOT NULL,
    orden integer NOT NULL,
    tipo_dato_salida character varying(30) NOT NULL,
    longitud_maxima integer,
    precision_numerica integer,
    escala_numerica integer,
    formato_salida character varying(100),
    origen_dato character varying(30) NOT NULL,
    tabla_origen character varying(150),
    columna_origen character varying(150),
    alias_origen character varying(100),
    valor_constante character varying(255),
    funcion_java character varying(100),
    expresion_sql text,
    parametros_json jsonb NOT NULL DEFAULT '{}'::jsonb,
    obligatorio boolean NOT NULL DEFAULT true,
    permite_nulo boolean NOT NULL DEFAULT true,
    incluir_salida boolean NOT NULL DEFAULT true,
    estado smallint NOT NULL DEFAULT 1,
    descripcion text,
    observaciones text,
    creado_en timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP,
    modificado_en timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP,
    creado_por_id bigint,
    modificado_por_id bigint,
    CONSTRAINT sipro_parametros_columnas_creffsos_nombre_key UNIQUE (nombre_columna),
    CONSTRAINT sipro_parametros_columnas_creffsos_orden_key UNIQUE (orden),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_nombre_upper CHECK (nombre_columna = UPPER(nombre_columna)),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_tipo_dato CHECK (tipo_dato_salida IN ('STRING', 'INTEGER', 'NUMERIC', 'DATE', 'BOOLEAN')),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_origen CHECK (origen_dato IN ('DIRECTO', 'CONSTANTE', 'REGLA', 'LOOKUP', 'SECUENCIA', 'VACIO')),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_estado CHECK (estado IN (0, 1)),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_longitud CHECK (longitud_maxima IS NULL OR longitud_maxima > 0),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_precision CHECK (precision_numerica IS NULL OR precision_numerica > 0),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_escala_min CHECK (escala_numerica IS NULL OR escala_numerica >= 0),
    CONSTRAINT chk_sipro_parametros_columnas_creffsos_escala_max CHECK (
        escala_numerica IS NULL
        OR precision_numerica IS NULL
        OR escala_numerica <= precision_numerica
    ),
    CONSTRAINT fk_sipro_parametros_columnas_creffsos_creado_por FOREIGN KEY (creado_por_id)
        REFERENCES public.usuario_persona(id_usuario),
    CONSTRAINT fk_sipro_parametros_columnas_creffsos_modificado_por FOREIGN KEY (modificado_por_id)
        REFERENCES public.usuario_persona(id_usuario)
);

CREATE INDEX IF NOT EXISTS idx_sipro_parametros_columnas_creffsos_activas
    ON public.sipro_parametros_columnas_creffsos (orden)
    WHERE estado = 1 AND incluir_salida = true;

CREATE INDEX IF NOT EXISTS idx_sipro_parametros_columnas_creffsos_funcion_java
    ON public.sipro_parametros_columnas_creffsos (funcion_java)
    WHERE funcion_java IS NOT NULL;

COMMENT ON TABLE public.sipro_parametros_columnas_creffsos IS
    'Configuración detallada de columnas de salida del archivo CREFFSOS para generación parametrizada desde Java.';

COMMENT ON COLUMN public.sipro_parametros_columnas_creffsos.funcion_java IS
    'Nombre de la estrategia o método Java/Spring que interpreta la regla de negocio de la columna.';

COMMENT ON COLUMN public.sipro_parametros_columnas_creffsos.parametros_json IS
    'Parámetros estructurados para la estrategia Java; evita códigos duros y facilita agregar o quitar columnas.';

