ON CONFLICT (nombre_columna) DO UPDATE
SET
    orden = EXCLUDED.orden,
    tipo_dato_salida = EXCLUDED.tipo_dato_salida,
    longitud_maxima = EXCLUDED.longitud_maxima,
    precision_numerica = EXCLUDED.precision_numerica,
    escala_numerica = EXCLUDED.escala_numerica,
    formato_salida = EXCLUDED.formato_salida,
    origen_dato = EXCLUDED.origen_dato,
    tabla_origen = EXCLUDED.tabla_origen,
    columna_origen = EXCLUDED.columna_origen,
    alias_origen = EXCLUDED.alias_origen,
    valor_constante = EXCLUDED.valor_constante,
    funcion_java = EXCLUDED.funcion_java,
    expresion_sql = EXCLUDED.expresion_sql,
    parametros_json = EXCLUDED.parametros_json,
    obligatorio = EXCLUDED.obligatorio,
    permite_nulo = EXCLUDED.permite_nulo,
    incluir_salida = EXCLUDED.incluir_salida,
    estado = EXCLUDED.estado,
    descripcion = EXCLUDED.descripcion,
    observaciones = EXCLUDED.observaciones,
    modificado_en = CURRENT_TIMESTAMP;

INSERT INTO public.sipro_parametros_columnas (
    categoria,
    nombre_columna,
    orden,
    descripcion,
    estado
)
SELECT
    'CREFFSOS' AS categoria,
    nombre_columna,
    orden,
    LEFT(COALESCE(descripcion, ''), 255) AS descripcion,
    estado
FROM public.sipro_parametros_columnas_creffsos
ON CONFLICT (categoria, nombre_columna) DO UPDATE
SET
    orden = EXCLUDED.orden,
    descripcion = EXCLUDED.descripcion,
    estado = EXCLUDED.estado;

WITH max_documento AS (
    SELECT COALESCE(MAX(documento), 0)::character varying AS valor
    FROM public.sipro_detalle_consolidado_registros
    WHERE documento IS NOT NULL AND documento > 0
), parametros AS (
    SELECT
        'CREFFSOS_RUTA_SALIDA'::character varying AS clave,
        $$\\sbmdebns03\CornerStone\componentes\DIR SERV EMPRESA Y GBNO\GCIA CARTERA EMPRESA Y GBNO$$::character varying AS valor,
        'STRING'::character varying AS tipo,
        'Ruta compartida donde debe publicarse el consolidado CREFFSOS.'::text AS descripcion
    UNION ALL
    SELECT 'CREFFSOS_NOMBRE_ARCHIVO_SALIDA', 'CREFFSOS.csv', 'STRING', 'Nombre del archivo final a generar para CREFFSOS.'
    UNION ALL
    SELECT 'CREFFSOS_FORMATO_SALIDA', 'CSV', 'STRING', 'Formato de salida actual del consolidado CREFFSOS; permite cambiar a CSV, TSV o XLSX sin rediseñar la tabla.'
    UNION ALL
    SELECT 'CREFFSOS_HOJA_XLSX', 'CREFFSOS', 'STRING', 'Nombre de la hoja de trabajo al exportar el consolidado CREFFSOS a Excel.'
    UNION ALL
    SELECT 'CREFFSOS_INCLUIR_ENCABEZADO', 'false', 'BOOLEAN', 'Indica si el archivo final generado debe incluir fila de encabezado.'
    UNION ALL
    SELECT 'CREFFSOS_DOCUMENTO_CONSECUTIVO_INICIAL', valor, 'INTEGER', 'Valor base inicial para la secuencia de DOCUMENTO cuando el origen no traiga dato.'
    FROM max_documento
    UNION ALL
    SELECT 'CREFFSOS_DOCUMENTO_CONSECUTIVO_ACTUAL', valor, 'INTEGER', 'Último consecutivo utilizado para la regla de DOCUMENTO cuando el origen no traiga dato.'
    FROM max_documento
)
INSERT INTO public.sipro_parametros_unico (
    clave,
    valor,
    tipo,
    descripcion
)
SELECT
    clave,
    valor,
    tipo,
    descripcion
FROM parametros
ON CONFLICT (clave) DO UPDATE
SET
    valor = EXCLUDED.valor,
    tipo = EXCLUDED.tipo,
    descripcion = EXCLUDED.descripcion,
    modificado_en = CURRENT_TIMESTAMP;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'appuser') THEN
        EXECUTE 'ALTER TABLE public.sipro_parametros_columnas_creffsos OWNER TO appuser';
    END IF;
END $$;